select.if:
SELECT ${valueName} as "value", ${labelName} as "label" FROM ${tableName}
and ${labelName} like '%' || #{search.labelContent} || '%'
and rownum <= #{search.number}

SELECT
    ${valueName} as "value",
    ${labelName} as "label"
FROM
    ${tableName}
where
    ${valueName}

        #{item}

mapper.select:
SELECT ${valueName} as "value", ${labelName} as "label" FROM ${tableName} WHERE 1=1
and ${other}
ORDER BY "label" ASC

select.if:
SELECT T1.ID AS "value", T1.SHIP_NAME as "label", T1.TOTAL_WEIGHT as "totalWeight", T1.NET_WEIGHT as "netWeight", T1.SHIP_WIDTH as "shipWidth", T1.DWT as "dwt", T1.FULL_LOAD_WATER as "fullLoadWater", T1.EMPTY_LOAD_WATER as "emptyLoadWater", T1.SHIP_LENGTH as "shipLength", T1.CAPTAIN_PHONE as "captainPhone", T1.IMO as "imo", T1.CALL_NO as "callNo" FROM M_SHIP T1 WHERE 1=1
and (FUNC_SHIP_NAME_REPLACE(T1.SHIP_NAME) like #{labelContent} OR T1.SHIP_NAME_EN LIKE #{labelContent} OR T1.SHORTHAND_CODE LIKE #{labelContent} )
and rownum <= #{search.number}

SELECT T1.ID AS "shipvoyageId", T2.ID AS "value", CONCAT(CONCAT(T1.SHIP_NAME, '_') , T2.VOYAGE) as "label", T2.CARGO_CATEGORY_NAME as "cargoCategoryName", T2.CUSTOMER_NAME as "shipAgentName", T1.START_PORT_NAME as "startPortName", T1.END_PORT_NAME as "endPortName", TO_CHAR(T1.ARRIVAL_TIME_PLAN, 'YYYY-MM-DD') as "arrivalTimePlan", T1.SCN as "scn", T1.SHIP_NAME as "shipName", T2.VOYAGE as "voyage", T2.LOAD_UNLOAD as "loadUnload", T2.CARGO_CATEGORY_CODE as "cargoCategoryCode", T2.CARGO_CATEGORY_NAME as "cargoCategoryName", CARGO_NUM as "cargoNum" FROM T_DIS_SHIPVOYAGE T1 JOIN T_DIS_SHIPVOYAGE_ITEM T2 ON T1.ID = T2.SHIPVOYAGE_ID WHERE 1=1
and (T1.SHIP_NAME like #{labelContent} OR T2.VOYAGE LIKE #{labelContent} OR CONCAT( CONCAT( T1.SHIP_NAME, '_' ), T2.VOYAGE ) LIKE #{labelContent})
and rownum <= #{search.number}

SELECT T1.ID AS "value", CONCAT(CONCAT(T1.SHIP_NAME, '_') , T1.SCN) as "label", T1.SCN as "scn", T1.SHIP_NAME as "shipName", T1.SHIP_ID as "shipId" FROM T_DIS_SHIPVOYAGE T1 WHERE 1=1
and (T1.SHIP_NAME like #{labelContent} OR T1.SCN LIKE #{labelContent})
and rownum <= #{search.number}

SELECT T1.ID AS "value", CONCAT(CONCAT(T1.SHIP_NAME, '_') , T1.SCN) as "label", T1.SCN as "scn", T1.SHIP_NAME as "shipName", T1.SHIP_ID as "shipId" FROM T_DIS_SHIPVOYAGE T1 WHERE T1.SHIP_STATUS_CODE IN ('30','50','60', '70','80','90','100','110') AND 1=1
and (T1.SHIP_NAME like #{labelContent} OR T1.SCN LIKE #{labelContent})
and rownum <= #{search.number}

SELECT T1.BHT_ID AS "value", T1.CUSTOMER_NAME as "label" FROM T_BUS_CUSTOMER T1 WHERE T1.STATUS = '10'
and (T1.CUSTOMER_NAME like #{labelContent} OR T1.CUSTOMER_SHORT_NAME LIKE #{labelContent} OR T1.SHORTHAND_CODE LIKE #{labelContent})
and rownum <= #{search.number}

SELECT T1. ID AS "value", CONCAT ( CONCAT ( CONCAT ( CONCAT ( CONCAT ( CONCAT ( CONCAT ( T1.SHIP_NAME || '_' || T2.VOYAGE, '/' ), CONCAT (T1.CARGO_INFO_NO, '/') ), CONCAT ( CONCAT (T1.COMPANY_NAME, '/'), CONCAT (T1.CARGO_OWNER_NAME, '/') ) ), CONCAT (T1.CARGO_AGENT_NAME, '/') ), CONCAT (T1.CARGO_NAME, '/') ), CONCAT (T1.TRADE_TYPE, '/') ), T1.PACKING_NAME ) AS "label", T1.CARGO_INFO_NO as "cargoInfoNo", T1.SHIPVOYAGE_ID as "shipvoyageId", T1.SHIPVOYAGE_ITEM_ID as "shipvoyageItemId", T1.SCN as "scn", T1.SHIP_NAME as "shipName", T1.COMPANY_ID as "companyId", T1.COMPANY_NAME as "companyName", T1.CARGO_OWNER_ID as "cargoOwnerId", T1.CARGO_OWNER_NAME as "cargoOwnerName", T1.CARGO_AGENT_ID as "cargoAgentId", T1.CARGO_AGENT_NAME as "cargoAgentName", T1.CARGO_CODE as "cargoCode", T1.CARGO_NAME as "cargoName", T1.TRADE_TYPE as "tradeType", T1.PACKING_CODE as "packingCode", T1.PACKING_NAME as "packingName", T1.QUANTITY as "quantity", T1.TON as "ton" FROM T_BUS_CARGO_INFO T1 left join T_DIS_SHIPVOYAGE_ITEM T2 ON T1.SHIPVOYAGE_ITEM_ID = T2.ID WHERE (T1.IS_LOGOUT != 10 or T1.IS_LOGOUT is null)
and (T1.CARGO_OWNER_NAME LIKE #{labelContent} OR T1.CARGO_INFO_NO LIKE #{labelContent} OR T1.CARGO_AGENT_NAME LIKE #{labelContent} OR T1.CARGO_NAME LIKE #{labelContent} OR T1.PACKING_NAME LIKE #{labelContent} OR T1.TRADE_TYPE LIKE #{labelContent} OR T1.SHIP_NAME LIKE #{labelContent} )
and rownum <= #{search.number}

SELECT
    T1.ID AS "value",
    T1.PORT_NAME as "label"
FROM
    M_PORT T1
WHERE
    1=1


        and (T1.PORT_CODE like #{labelContent}
        OR T1.PORT_NAME LIKE #{labelContent}
        )


        and rownum <= #{search.number}

SELECT CONCAT(CONCAT(CONCAT(CONCAT(M3.STORAGE_YARD_NM, '/'), M2.STORAGE_YARD_NM), '/'), M1.STORAGE_YARD_NM) as "label", CONCAT(CONCAT(CONCAT(CONCAT(M3.STORAGE_YARD_NM, '/'), M2.STORAGE_YARD_NM), '/'), M1.STORAGE_YARD_NM) as "massNameFull", M1.ID as "value", M1.ID as "massId", M1.STORAGE_YARD_NM as "massName", M3.ID as "storehouseId", M3.STORAGE_YARD_NM as "storehouseName", M2.ID as "regionId", M2.STORAGE_YARD_NM as "regionName" FROM M_STORAGE_YARD M1, M_STORAGE_YARD M2, M_STORAGE_YARD M3 WHERE M1.STORAGE_YARD_LEVEL = '3' AND M1.PARENT_ID = M2.ID AND M2.STORAGE_YARD_LEVEL = '2' AND M2.PARENT_ID = M3.ID AND M3.STORAGE_YARD_LEVEL = '1'
and (M1.STORAGE_YARD_NM like UPPER(#{labelContent}) OR M2.STORAGE_YARD_NM LIKE UPPER(#{labelContent}) OR M3.STORAGE_YARD_NM LIKE UPPER(#{labelContent}) )
and rownum <= #{search.number}

SELECT CONCAT(CONCAT(M3.STORAGE_YARD_NM, '/'), M2.STORAGE_YARD_NM) as "label", CONCAT(CONCAT(M3.STORAGE_YARD_NM, '/'), M2.STORAGE_YARD_NM) as "massNameFull", M2.ID as "value", M3.ID as "storehouseId", M3.STORAGE_YARD_NM as "storehouseName", M2.ID as "regionId", M2.STORAGE_YARD_NM as "regionName" FROM M_STORAGE_YARD M2, M_STORAGE_YARD M3 WHERE M2.STORAGE_YARD_LEVEL = '2' AND M2.PARENT_ID = M3.ID AND M3.STORAGE_YARD_LEVEL = '1'
and ( M2.STORAGE_YARD_NM LIKE UPPER(#{labelContent}) OR M3.STORAGE_YARD_NM LIKE UPPER(#{labelContent}) )
and rownum <= #{search.number}

mapper.select:
select MODEL_CODE as "value", MODEL_NAME as "label" from m_machine_type_model
MAC_TYPE_CODE = #{macTypeCode}
order by MODEL_CODE

SELECT M1.ID AS "id", M1.COMPANY_ID AS "companyId", M1.COMPANY_NAME AS "companyName", M1.TRUST_NO AS "trustNo", M1.PROCESS_CODE AS "processCode", M1.PROCESS_NAME AS "processName", M1.CUSTOMER_NAME AS "customerName", M1.SETTLEMENT_BASIS_CODE as "settlementBasisCode", M1.SETTLEMENT_BASIS_NAME as "settlementBasisName", M1.REMARK AS "remark", M1.SHIPVOYAGE_ID AS "shipvoyageId", M1.SHIPVOYAGE_ITEM_ID AS "shipvoyageItemId", T2.LOAD_UNLOAD AS "loadUnload", CONCAT( CONCAT( M1.SHIP_NAME, '/' ), T2.VOYAGE ) AS "voyage", T3.BERTH_ID AS "berthId", T3.BERTH_NAME AS "berthName", 122 AS "cars", M1.PLAN_QUANTITY AS "planQuantity", M1.PLAN_TON AS "planTon" , T3.CARGO_OWNER_NAME AS "cargoOwnerName", T4.CARGO_AGENT_NAME AS "cargoAgentName", T5.CARGO_NAME AS "cargoName", M1.TYPE AS "type" FROM T_BUS_TRUST M1 LEFT JOIN T_DIS_SHIPVOYAGE_ITEM T2 ON M1.SHIPVOYAGE_ITEM_ID = T2.ID LEFT JOIN T_DIS_SHIPVOYAGE T3 ON T2.SHIPVOYAGE_ID = T3.ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_NAME,TRUST_ID, REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_ID ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_ID ), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T3 ON M1.ID = T3.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_AGENT_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_AGENT_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_AGENT_NAME,TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T4 ON M1.ID = T4.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_NAME,TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T5 ON M1.ID = T5.TRUST_ID
#{item, jdbcType=VARCHAR}
M1.STATUS IN ('30', '40')
AND M1.TRUST_TYPE = #{trustType}
AND T2.ID = #{shipvoyageItemId, jdbcType=BIGINT}
AND M1.CUSTOMER_NAME LIKE #{customerNameBind}
AND M1.TRUST_NO LIKE #{trustNo_like}
ORDER BY M1.TRUST_NO DESC, M1.PROCESS_CODE

SELECT M1.ID, M1.CREATE_TIME, M1.START_TIME, M1.END_TIME, M1.COMPANY_ID , M1.COMPANY_NAME, M1.TRUST_NO, M1.PROCESS_CODE, M1.PROCESS_NAME, M1.CUSTOMER_NAME, M1.SETTLEMENT_BASIS_CODE, M1.SETTLEMENT_BASIS_NAME, M1.REMARK, M1.SHIPVOYAGE_ID, M1.SHIPVOYAGE_ITEM_ID, T2.LOAD_UNLOAD , CONCAT( CONCAT( M1.SHIP_NAME, '/' ), T2.VOYAGE ) AS "voyage", CONCAT( CONCAT( M1.SHIP_NAME, '/' ), T2.VOYAGE ) AS "shipNameVoyages", T3.BERTH_ID, T3.BERTH_NAME, 122 AS "cars", M1.PLAN_QUANTITY, M1.PLAN_TON, T3.CARGO_OWNER_NAME, T4.CARGO_AGENT_NAME, T5.CARGO_NAME, M1.TYPE, T3.SHIP_STATUS_CODE, T3.SHIP_STATUS_NAME, M1.RELEASE_TIME
FROM T_BUS_TRUST M1 LEFT JOIN T_DIS_SHIPVOYAGE_ITEM T2 ON M1.SHIPVOYAGE_ITEM_ID = T2.ID LEFT JOIN T_DIS_SHIPVOYAGE T3 ON T2.SHIPVOYAGE_ID = T3.ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_NAME,TRUST_ID, REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_ID ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_ID ), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T3 ON M1.ID = T3.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_AGENT_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_AGENT_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_AGENT_NAME,TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T4 ON M1.ID = T4.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_NAME,TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T5 ON M1.ID = T5.TRUST_ID LEFT JOIN T_BUS_TRUST_CARGO TBTC ON M1.ID = TBTC.TRUST_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID
#{item, jdbcType=VARCHAR}
M1.STATUS IN ('30', '40')
AND M1.TRUST_TYPE IN ('1','3')
AND M1.TRUST_TYPE = #{trustType}
and ( M1.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId} OR TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId} )
AND M1.CUSTOMER_NAME LIKE #{customerNameBind}
AND M1.TRUST_NO LIKE #{trustNo_like}
AND TBTC.PACKING_CODE = #{packageCode}
AND T3.SHIP_STATUS_CODE IN
#{item,jdbcType=VARCHAR}
AND TO_DATE(TO_CHAR(M1.CREATE_TIME, 'yyyy-MM-dd'), 'yyyy-MM-dd') >= TO_DATE( #{beginDate},'YYYY-MM-DD' )
AND TO_DATE(TO_CHAR(M1.CREATE_TIME, 'yyyy-MM-dd'), 'yyyy-MM-dd') <= TO_DATE( #{endDate},'YYYY-MM-DD' )
group by M1.ID, M1.CREATE_TIME, M1.COMPANY_ID, M1.COMPANY_NAME, M1.TRUST_NO, M1.PROCESS_CODE, M1.PROCESS_NAME, M1.CUSTOMER_NAME, M1.SETTLEMENT_BASIS_CODE, M1.SETTLEMENT_BASIS_NAME, M1.REMARK, M1.SHIPVOYAGE_ID, M1.SHIPVOYAGE_ITEM_ID, T2.LOAD_UNLOAD, CONCAT( CONCAT( M1.SHIP_NAME, '/' ), T2.VOYAGE ), T3.BERTH_ID, T3.BERTH_NAME, 122, M1.PLAN_QUANTITY, M1.PLAN_TON, T3.CARGO_OWNER_NAME, T4.CARGO_AGENT_NAME, T5.CARGO_NAME, M1.TYPE, M1.RELEASE_TIME, M1.START_TIME, T3.SHIP_STATUS_CODE, T3.SHIP_STATUS_NAME, M1.END_TIME
ORDER BY M1.CREATE_TIME DESC

select.if:
SELECT T1.CARGO_CODE AS "value", T1.CARGO_NAME as "label", T1.WORK_TYPE as "workType" FROM M_CARGO T1 WHERE T1.DEL_FLAG = '0' AND T1.STATUS = '1'
and (T1.CARGO_NAME like #{labelContent} OR T1.CARGO_CODE LIKE #{labelContent} OR T1.SHORTHAND_CODE like #{labelContent})
and rownum <= #{search.number}

SELECT T1.BHT_ID AS "value", T1.CARGO_NAME as "label", T1.WORK_TYPE as "workType" FROM M_CARGO T1 WHERE T1.DEL_FLAG = '0' AND T1.STATUS = '1'
and (T1.CARGO_NAME like #{labelContent} OR T1.BHT_ID LIKE #{labelContent} OR T1.SHORTHAND_CODE like #{labelContent})
and rownum <= #{search.number}

mapper.select:
SELECT * FROM ( SELECT TDSI.ID, TDS.SHIP_NAME || '_' || TDSI.VOYAGE || '/' || TDS.SCN || '/' || TDSI.SHIP_STATUS_NAME || '/' || MDD_IN_OUT_TYPE.DICT_LABEL || '/' || TO_CHAR(TDS.ARRIVAL_TIME_PLAN, 'YYYY-MM-DD HH24:MI:SS') || '/' || TDS.START_PORT_NAME || '->' || TDS.END_PORT_NAME LABEL, TDS.ID SHIPVOYAGE_ID, TDS.SHIP_NAME, TDSI.VOYAGE, MS.HATCH_NUM, TDSI.IMP_EXP, DECODE(TDSI.IMP_EXP, 'IN', '进口', ( DECODE(TDSI.IMP_EXP, 'OUT', '出口', ''))) IMP_EXP_LABEL, TDSI.TRADE_TYPE FROM T_DIS_SHIPVOYAGE_ITEM TDSI JOIN T_DIS_SHIPVOYAGE TDS ON TDSI.SHIPVOYAGE_ID = TDS.ID JOIN M_SHIP MS ON TDS.SHIP_ID = MS.ID LEFT JOIN M_DICT_DATA MDD_IN_OUT_TYPE ON (MDD_IN_OUT_TYPE.DICT_TYPE = 'IN_OUT_TYPE' AND TDSI.IMP_EXP = MDD_IN_OUT_TYPE.DICT_VALUE)
AND (
TDSI.ID = #{valueContent, jdbcType=BIGINT}
OR
TDS.SHIP_NAME || '_' || TDSI.VOYAGE || '/' || TDS.SCN || '/' || TDSI.SHIP_STATUS_NAME || '/' || MDD_IN_OUT_TYPE.DICT_LABEL || '/' || TO_CHAR(TDS.ARRIVAL_TIME_PLAN, 'YYYY-MM-DD HH24:MI:SS') || '/' || TDS.START_PORT_NAME || '->' || TDS.END_PORT_NAME LIKE #{labelContentLike, jdbcType=VARCHAR}
)
ORDER BY TDS.ARRIVAL_TIME_PLAN DESC ) TEMP WHERE ROWNUM <= #{number, jdbcType=BIGINT}

SELECT * FROM ( SELECT TDSI.ID, TDS.SHIP_NAME || '_' || TDSI.VOYAGE || '/' || TDS.SCN || '/' || TDSI.SHIP_STATUS_NAME || '/' || MDD_IN_OUT_TYPE.DICT_LABEL || '/' || TO_CHAR(TDS.ARRIVAL_TIME_PLAN, 'YYYY-MM-DD HH24:MI:SS') || '/' || TDS.START_PORT_NAME || '->' || TDS.END_PORT_NAME LABEL, TDS.ID SHIPVOYAGE_ID, TDS.SHIP_NAME, TDSI.VOYAGE, MS.HATCH_NUM, TDSI.IMP_EXP, DECODE(TDSI.IMP_EXP, 'IN', '进口', ( DECODE(TDSI.IMP_EXP, 'OUT', '出口', ''))) IMP_EXP_LABEL, TDSI.TRADE_TYPE FROM T_DIS_SHIPVOYAGE_ITEM TDSI JOIN T_DIS_SHIPVOYAGE TDS ON TDSI.SHIPVOYAGE_ID = TDS.ID JOIN M_SHIP MS ON TDS.SHIP_ID = MS.ID LEFT JOIN M_DICT_DATA MDD_IN_OUT_TYPE ON (MDD_IN_OUT_TYPE.DICT_TYPE = 'IN_OUT_TYPE' AND TDSI.IMP_EXP = MDD_IN_OUT_TYPE.DICT_VALUE)
AND TDS.WHARF NOT IN ('集装箱', '晨鸣')
AND (
TDSI.ID = #{valueContent, jdbcType=BIGINT}
OR
TDS.SHIP_NAME || '_' || TDSI.VOYAGE || '/' || TDS.SCN || '/' || TDSI.SHIP_STATUS_NAME || '/' || MDD_IN_OUT_TYPE.DICT_LABEL || '/' || TO_CHAR(TDS.ARRIVAL_TIME_PLAN, 'YYYY-MM-DD HH24:MI:SS') || '/' || TDS.START_PORT_NAME || '->' || TDS.END_PORT_NAME LIKE #{labelContentLike, jdbcType=VARCHAR}
)
ORDER BY TDS.ARRIVAL_TIME_PLAN DESC ) TEMP WHERE ROWNUM <= #{number, jdbcType=BIGINT}

SELECT * FROM ( SELECT TDSI.ID, TDS.SHIP_NAME || '_' || TDSI.VOYAGE || '/' || TDS.SCN || '/' || TDS.SHIP_STATUS_NAME || '/' || MDD_IN_OUT_TYPE.DICT_LABEL || '/' || TO_CHAR(TDS.ARRIVAL_TIME_PLAN, 'YYYY-MM-DD HH24:MI:SS') || '/' || TDS.START_PORT_NAME || '->' || TDS.END_PORT_NAME LABEL, TDS.ID SHIPVOYAGE_ID, TDS.SHIP_NAME, TDSI.VOYAGE, MS.HATCH_NUM, TDSI.IMP_EXP, DECODE(TDSI.IMP_EXP, 'IN', '进口', ( DECODE(TDSI.IMP_EXP, 'OUT', '出口', ''))) IMP_EXP_LABEL, TDSI.TRADE_TYPE, TDSI.CUSTOMER_ID, TDSI.CUSTOMER_NAME FROM T_DIS_SHIPVOYAGE_ITEM TDSI JOIN T_DIS_SHIPVOYAGE TDS ON TDSI.SHIPVOYAGE_ID = TDS.ID JOIN M_SHIP MS ON TDS.SHIP_ID = MS.ID LEFT JOIN M_DICT_DATA MDD_IN_OUT_TYPE ON (MDD_IN_OUT_TYPE.DICT_TYPE = 'IN_OUT_TYPE' AND TDSI.IMP_EXP = MDD_IN_OUT_TYPE.DICT_VALUE)
AND TDS.WHARF NOT IN ('集装箱', '晨鸣')
and TDSI.SHIP_STATUS_CODE not in ('120','00') AND (
TDSI.ID = #{valueContent, jdbcType=BIGINT}
OR
TDS.SHIP_NAME || '_' || TDSI.VOYAGE || '/' || TDS.SCN || '/' || TDSI.SHIP_STATUS_NAME || '/' || MDD_IN_OUT_TYPE.DICT_LABEL || '/' || TO_CHAR(TDS.ARRIVAL_TIME_PLAN, 'YYYY-MM-DD HH24:MI:SS') || '/' || TDS.START_PORT_NAME || '->' || TDS.END_PORT_NAME LIKE #{labelContentLike, jdbcType=VARCHAR}
)
AND (
TDSI.ID = #{valueContent, jdbcType=BIGINT}
OR
TDS.SHIP_NAME || '_' || TDSI.VOYAGE || '/' || TDS.SCN || '/' || TDSI.SHIP_STATUS_NAME || '/' || MDD_IN_OUT_TYPE.DICT_LABEL || '/' || TO_CHAR(TDS.ARRIVAL_TIME_PLAN, 'YYYY-MM-DD HH24:MI:SS') || '/' || TDS.START_PORT_NAME || '->' || TDS.END_PORT_NAME LIKE #{labelContentLike, jdbcType=VARCHAR}
)
ORDER BY TDS.ARRIVAL_TIME_PLAN DESC ) TEMP WHERE ROWNUM <= #{number, jdbcType=BIGINT}

select.if:
SELECT T1.CARGO_CODE AS "value", CASE WHEN T1.SIGN IS NOT NULL THEN T1.CARGO_NAME || '(' || T1.SIGN || ')' ELSE T1.CARGO_NAME END AS "label", T1.WORK_TYPE as "workType", DECODE(T1.STATUS, '1', 0, 1) "disabled" FROM M_CARGO T1 WHERE T1.DEL_FLAG = '0' AND T1.STATUS = '1'
and (T1.CARGO_NAME like #{labelContent} OR T1.CARGO_CODE LIKE #{labelContent} OR T1.SHORTHAND_CODE like #{labelContent})
and rownum <= #{search.number}

SELECT T1.CARGO_CODE AS "value", CASE WHEN T1.SIGN IS NOT NULL THEN T1.CARGO_NAME || '(' || T1.SIGN || ')' ELSE T1.CARGO_NAME END AS "label", T1.WORK_TYPE as "workType" FROM M_CARGO T1 WHERE T1.DEL_FLAG = '0' AND T1.STATUS = '1'
and (T1.CARGO_NAME like #{labelContent} OR T1.CARGO_CODE LIKE #{labelContent} OR T1.SHORTHAND_CODE like #{labelContent})
and rownum <= #{search.number}

mapper.select:
SELECT PROCESS_CD as "value", PROCESS_NM as "label", NEW_PROCESS AS "newProcess" FROM M_WORK_PROCESS WHERE length(process_cd) > 5 and process_cd like #{parent,jdbcType=VARCHAR}
AND IS_TALLY_COURSE = #{isTallyCourse,jdbcType=VARCHAR}
AND IS_TALLY_TON = #{isTallyTon,jdbcType=VARCHAR}
ORDER BY "label" ASC

SELECT PROCESS_CD as "value", PROCESS_NM as "label", NEW_PROCESS AS "newProcess" FROM M_WORK_PROCESS WHERE NEW_PROCESS = '1' and length(process_cd) > 5 and process_cd like #{parent,jdbcType=VARCHAR}
AND IS_TALLY_COURSE = #{isTallyCourse,jdbcType=VARCHAR}
AND IS_TALLY_TON = #{isTallyTon,jdbcType=VARCHAR}
ORDER BY "label" ASC

select.if:
SELECT T1.ID AS "value", T1.CARGO_INFO_NO as "label" FROM T_BUS_CARGO_INFO T1 WHERE 1 = 1
and T1.CARGO_INFO_NO like #{labelContent}
and rownum <= #{search.number}

SELECT T1.ID AS "shipvoyageId", T2.ID AS "value", CONCAT(CONCAT(T1.SHIP_NAME, '_') , T2.VOYAGE) as "label", T2.CARGO_CATEGORY_NAME as "cargoCategoryName", T2.CUSTOMER_NAME as "shipAgentName", T1.START_PORT_NAME as "startPortName", T1.END_PORT_NAME as "endPortName", TO_CHAR(T1.ARRIVAL_TIME_PLAN, 'YYYY-MM-DD') as "arrivalTimePlan", T1.SCN as "scn", T1.SHIP_NAME as "shipName", T2.VOYAGE as "voyage", T2.LOAD_UNLOAD as "loadUnload", T2.CARGO_CATEGORY_CODE as "cargoCategoryCode", T2.CARGO_CATEGORY_NAME as "cargoCategoryName", CARGO_NUM as "cargoNum" FROM T_DIS_SHIPVOYAGE T1 JOIN T_DIS_SHIPVOYAGE_ITEM T2 ON T1.ID = T2.SHIPVOYAGE_ID WHERE T1.SHIP_STATUS_CODE NOT IN ('120')
and (T1.SHIP_NAME like #{labelContent} OR T2.VOYAGE LIKE #{labelContent} OR CONCAT( CONCAT( T1.SHIP_NAME, '_' ), T2.VOYAGE ) LIKE #{labelContent})
and rownum <= #{search.number}

mapper.select:
SELECT distinct M1.STOP_REASON_NAME "label" , M1.ID "value" FROM M_STOP_REASON M1
and m1.STOP_REASON_CLASS_CODE = #{stopType,jdbcType=VARCHAR}
and m1.STOP_REASON_TYPE_CODE = #{stopHourType,jdbcType=VARCHAR}
